"""
Parameterized generator for GH353_hrm_3716.

Source PR:    https://github.com/arii/hrm/pull/3716
Source Issue: https://github.com/arii/hrm/issues/3566

Seed varies: renames 'changes' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH353_hrm_3716'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH353_hrm_3716'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('changes', 'changes' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH353_hrm_3716',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'arii/hrm',
                "pr_number": 3716,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/arii/hrm/pull/3716",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'app/client/experimental/components/ExperimentalAnalyticsPage.tsx': '// app/client/experimental/components/ExperimentalAnalyticsPage.tsx\n\'use client\'\nimport { useMemo } from \'react\'\nimport { Container, Box, Button } from \'@mui/material\'\nimport dynamic from \'next/dynamic\'\nimport { useWebSocket } from \'@/context/WebSocketContext\'\nimport { useLocalWorkoutBuffer } from \'../useLocalWorkoutBuffer\'\nimport WorkoutSummary from \'./WorkoutSummary\'\nimport ZoneDistribution from \'./ZoneDistribution\'\n// Dynamically import HeartRateTimeSeries to ensure it\'s only rendered client-side\nconst HeartRateTimeSeries = dynamic(() => import(\'./HeartRateTimeSeries\'), {\n  ssr: false,\n})\nimport { estimateCaloriesBurned } from \'@/lib/calorie-estimation\'\nimport { useUserSettings } from \'@/context/UserSettingsContext\'\n\nconst ExperimentalAnalyticsPage = () => {\n  const { hrmData, timerData } = useWebSocket()\n  const timerStatus = timerData?.currentPhase\n  const [userSettings] = useUserSettings()\n\n  const workoutStatus =\n    timerStatus === \'WORK\' || timerStatus === \'REST\' ? \'running\' : \'idle\'\n\n  const { workoutData, resetWorkout, endWorkout } = useLocalWorkoutBuffer(\n    hrmData[0]?.value ?? 0,\n    workoutStatus\n  )\n\n  const totalDuration = workoutData.hrHistory.length\n\n  const caloriesBurned = useMemo(() => {\n    return workoutData.hrHistory.reduce((totalCalories, dataPoint) => {\n      const calories = estimateCaloriesBurned({\n        heartRate: dataPoint.hr,\n        age: userSettings.userAge || 30,\n        weightKg: userSettings.userWeight || 70,\n        durationMinutes: 1 / 60,\n      })\n      return totalCalories + calories\n    }, 0)\n  }, [workoutData.hrHistory, userSettings])\n\n  return (\n    <Container maxWidth="lg" sx={{ py: 4 }}>\n      <Box display="flex" flexDirection="column" gap={3}>\n        <WorkoutSummary\n          duration={totalDuration}\n          calories={caloriesBurned}\n          status={workoutData.status}\n        />\n        <Box display="flex" gap={3}>\n          <Box flex={1}>\n            <ZoneDistribution\n              timeInZones={workoutData.timeInZones}\n              userAge={userSettings.userAge}\n            />\n          </Box>\n          <Box flex={1}>\n            <HeartRateTimeSeries hrHistory={workoutData.hrHistory} />\n          </Box>\n        </Box>\n        <Box display="flex" justifyContent="flex-end" gap={2} mt={2}>\n          <Button\n            variant="contained"\n            color="primary"\n            onClick={endWorkout}\n            disabled={\n              workoutData.status !== \'running\' &&\n              workoutData.status !== \'paused\'\n            }\n          >\n            End Workout\n          </Button>\n          <Button variant="outlined" color="secondary" onClick={resetWorkout}>\n            Reset Data\n          </Button>\n        </Box>\n      </Box>\n    </Container>\n  )\n}\n\nexport default ExperimentalAnalyticsPage\n',
            'app/client/experimental/useLocalWorkoutBuffer.ts': "// app/client/experimental/useLocalWorkoutBuffer.ts\nimport { useEffect, useCallback, useRef } from 'react'\nimport { HrZoneName } from '@/utils/hr-zones'\nimport { getUserHrZones } from '@/utils/hr-zones'\nimport useLocalStorage from '@/hooks/useLocalStorage'\nimport { useUserSettings } from '@/context/UserSettingsContext'\n\n// Define the structure of a single heart rate data point\nexport interface HrDataPoint {\n  time: number\n  hr: number\n  zone: HrZoneName\n}\n\n// Define the structure for the entire workout session\nexport interface WorkoutSessionData {\n  startTime: number | null\n  endTime: number | null\n  status: 'idle' | 'running' | 'paused' | 'finished'\n  hrHistory: HrDataPoint[]\n  timeInZones: Record<HrZoneName, number>\n}\n\nconst initialWorkoutData: WorkoutSessionData = {\n  startTime: null,\n  endTime: null,\n  status: 'idle',\n  hrHistory: [],\n  timeInZones: {\n    [HrZoneName.WarmUp]: 0,\n    [HrZoneName.FatBurn]: 0,\n    [HrZoneName.Cardio]: 0,\n    [HrZoneName.Peak]: 0,\n    [HrZoneName.Max]: 0,\n    [HrZoneName.NoData]: 0,\n    [HrZoneName.Unknown]: 0,\n  },\n}\n\n/**\n * A hook to capture, manage, and persist workout data on the client-side,\n * synchronized with an external workout status.\n *\n * @param currentHr The current heart rate value from the WebSocket connection.\n * @param workoutStatus The current status of the workout from the main timer.\n */\nexport const useLocalWorkoutBuffer = (\n  currentHr: number,\n  workoutStatus: 'idle' | 'running' | 'paused'\n) => {\n  const [workoutData, setWorkoutData] = useLocalStorage<WorkoutSessionData>(\n    'experimentalWorkoutSession',\n    initialWorkoutData\n  )\n  const [userSettings] = useUserSettings()\n  const prevWorkoutStatusRef = useRef(workoutStatus)\n\n  const currentHrRef = useRef(currentHr)\n  useEffect(() => {\n    currentHrRef.current = currentHr\n  }, [currentHr])\n\n  const getZoneForHr = useCallback(\n    (hr: number): HrZoneName => {\n      if (hr <= 0) return HrZoneName.NoData // Handle no or invalid HR data\n      const age = userSettings.userAge || 30\n      const zones = getUserHrZones(age)\n      if (hr >= zones.max.min) return HrZoneName.Max\n      if (hr >= zones.peak.min) return HrZoneName.Peak\n      if (hr >= zones.cardio.min) return HrZoneName.Cardio\n      if (hr >= zones.fatBurn.min) return HrZoneName.FatBurn\n      return HrZoneName.WarmUp\n    },\n    [userSettings.userAge]\n  )\n\n  const recordHrData = useCallback(() => {\n    setWorkoutData((prevData) => {\n      if (prevData.status !== 'running') return prevData\n\n      const now = Date.now()\n      const latestHr = currentHrRef.current\n      const currentZone = getZoneForHr(latestHr)\n\n      const newHistory: HrDataPoint = {\n        time: now,\n        hr: latestHr,\n        zone: currentZone,\n      }\n      const updatedHistory = [...prevData.hrHistory, newHistory]\n\n      const updatedTimeInZones = { ...prevData.timeInZones }\n      updatedTimeInZones[currentZone] =\n        (updatedTimeInZones[currentZone] || 0) + 1\n\n      return {\n        ...prevData,\n        hrHistory: updatedHistory,\n        timeInZones: updatedTimeInZones,\n      }\n    })\n  }, [getZoneForHr, setWorkoutData])\n\n  useEffect(() => {\n    let intervalId: NodeJS.Timeout | null = null\n    // CHANGED: The interval now starts as soon as the workout is running,\n    // regardless of whether there's an active HR signal.\n    // This allows data collection to begin immediately and catch the HR\n    // signal as soon as it's available.\n    if (workoutData.status === 'running') {\n      intervalId = setInterval(recordHrData, 1000)\n    }\n    return () => {\n      if (intervalId) clearInterval(intervalId)\n    }\n  }, [workoutData.status, recordHrData])\n\n  useEffect(() => {\n    const prevStatus = prevWorkoutStatusRef.current\n    if (prevStatus !== workoutStatus) {\n      if (workoutStatus === 'running') {\n        setWorkoutData((prev) => {\n          if (prev.status === 'idle' || prev.status === 'finished') {\n            return {\n              ...initialWorkoutData,\n              status: 'running',\n              startTime: Date.now(),\n            }\n          }\n          if (prev.status === 'paused') {\n            return { ...prev, status: 'running' }\n          }\n          return prev\n        })\n      } else if (workoutStatus === 'paused') {\n        setWorkoutData((prev) =>\n          prev.status === 'running' ? { ...prev, status: 'paused' } : prev\n        )\n      } else if (workoutStatus === 'idle') {\n        // CHANGED: When the external timer goes idle (e.g., Tabata cycle ends),\n        // we now pause the local workout instead of finishing it.\n        // This preserves the session, allowing for continuous workouts that\n        // span multiple timer cycles.\n        setWorkoutData((prev) =>\n          prev.status === 'running' ? { ...prev, status: 'paused' } : prev\n        )\n      }\n    }\n    prevWorkoutStatusRef.current = workoutStatus\n  }, [workoutStatus, setWorkoutData])\n\n  const endWorkout = useCallback(() => {\n    setWorkoutData((prev) => ({\n      ...prev,\n      status: 'finished',\n      endTime: Date.now(),\n    }))\n  }, [setWorkoutData])\n\n  const resetWorkout = useCallback(() => {\n    setWorkoutData(initialWorkoutData)\n  }, [setWorkoutData])\n\n  return {\n    workoutData,\n    endWorkout,\n    resetWorkout,\n  }\n}\n",
            'tests/unit/hooks/useLocalWorkoutBuffer.test.tsx': "/**\n * @jest-environment jsdom\n */\n// tests/unit/hooks/useLocalWorkoutBuffer.test.tsx\nimport { renderHook, act, waitFor } from '@testing-library/react'\nimport { useLocalWorkoutBuffer } from '@/app/client/experimental/useLocalWorkoutBuffer'\nimport { useUserSettings } from '@/context/UserSettingsContext'\nimport { HrZoneName } from '@/utils/hr-zones'\n\n// Mock the useUserSettings hook\njest.mock('@/context/UserSettingsContext')\n\n// Mock useLocalStorage to behave like useState for testing logic\njest.mock('@/hooks/useLocalStorage', () => {\n  // eslint-disable-next-line @typescript-eslint/no-require-imports\n  const { useState } = require('react')\n  return {\n    __esModule: true,\n    default: <T,>(_key: string, initialValue: T) => {\n      // eslint-disable-next-line react-hooks/rules-of-hooks\n      const [state, setState] = useState(initialValue)\n      return [state, setState]\n    },\n  }\n})\n\ndescribe('useLocalWorkoutBuffer', () => {\n  const mockUseUserSettings = useUserSettings as jest.Mock\n\n  beforeEach(() => {\n    mockUseUserSettings.mockReturnValue([\n      { userAge: 30, userWeight: 70 },\n      () => {},\n    ])\n  })\n\n  it('should initialize with default data', () => {\n    const { result } = renderHook(() => useLocalWorkoutBuffer(0, 'idle'))\n    expect(result.current.workoutData.status).toBe('idle')\n    expect(result.current.workoutData.hrHistory).toHaveLength(0)\n  })\n\n  it('should start a workout when status changes to running', () => {\n    const { result, rerender } = renderHook(\n      ({ status }) => useLocalWorkoutBuffer(0, status),\n      { initialProps: { status: 'idle' } }\n    )\n    act(() => {\n      rerender({ status: 'running' })\n    })\n    expect(result.current.workoutData.status).toBe('running')\n    expect(result.current.workoutData.startTime).not.toBeNull()\n  })\n\n  it('should record HR data when running', async () => {\n    jest.useFakeTimers()\n    const { result, rerender } = renderHook(\n      ({ hr, status }) => useLocalWorkoutBuffer(hr, status),\n      { initialProps: { hr: 0, status: 'idle' } }\n    )\n\n    act(() => {\n      rerender({ hr: 120, status: 'running' })\n    })\n\n    await waitFor(() => {\n      expect(result.current.workoutData.status).toBe('running')\n    })\n\n    // Advance time in steps to allow state updates to settle\n    for (let i = 0; i < 3; i++) {\n      await act(async () => {\n        jest.advanceTimersByTime(1000)\n      })\n    }\n\n    expect(result.current.workoutData.hrHistory).toHaveLength(3)\n    expect(result.current.workoutData.hrHistory[0]?.hr).toBe(120)\n    expect(result.current.workoutData.timeInZones[HrZoneName.FatBurn]).toBe(3)\n    jest.useRealTimers()\n  })\n\n  it('should pause and resume a workout', () => {\n    const { result, rerender } = renderHook(\n      ({ status }) => useLocalWorkoutBuffer(0, status),\n      { initialProps: { status: 'idle' } }\n    )\n    act(() => {\n      rerender({ status: 'running' })\n    })\n    expect(result.current.workoutData.status).toBe('running')\n\n    act(() => {\n      rerender({ status: 'paused' })\n    })\n    expect(result.current.workoutData.status).toBe('paused')\n\n    act(() => {\n      rerender({ status: 'running' })\n    })\n    expect(result.current.workoutData.status).toBe('running')\n  })\n\n  it('should pause a workout when status changes to idle', () => {\n    const { result, rerender } = renderHook(\n      ({ status }) => useLocalWorkoutBuffer(0, status),\n      { initialProps: { status: 'idle' } }\n    )\n    act(() => {\n      rerender({ status: 'running' })\n    })\n    expect(result.current.workoutData.status).toBe('running')\n\n    act(() => {\n      rerender({ status: 'idle' })\n    })\n    expect(result.current.workoutData.status).toBe('paused')\n    expect(result.current.workoutData.endTime).toBeNull()\n  })\n\n  it('should reset workout data', () => {\n    const { result, rerender } = renderHook(\n      ({ status }) => useLocalWorkoutBuffer(0, status),\n      { initialProps: { status: 'idle' } }\n    )\n    act(() => {\n      rerender({ status: 'running' })\n    })\n    expect(result.current.workoutData.status).toBe('running')\n\n    act(() => {\n      result.current.resetWorkout()\n    })\n    expect(result.current.workoutData.status).toBe('idle')\n    expect(result.current.workoutData.startTime).toBeNull()\n  })\n})\n",
        }
